#include <bits/stdc++.h>
using namespace std;char L[128],R[128];string a,b,c;
void pre(char n){if(n=='.')return;a+=n;pre(L[n]);pre(R[n]);}
void in(char n){if(n=='.')return;in(L[n]);b+=n;in(R[n]);}
void post(char n){if(n=='.')return;post(L[n]);post(R[n]);c+=n;}
int main(){int n;cin>>n;for(int i=0;i<n;i++){char x,l,r;cin>>x>>l>>r;L[x]=l;R[x]=r;}pre('A');in('A');post('A');cout<<a<<"\n"<<b<<"\n"<<c<<"\n";}
